import React from 'react';
import { useParams, useNavigate } from 'react-router-dom';

const JobDetail = () => {
    const { id } = useParams();
    const navigate = useNavigate();

    // Simulasi data (Ganti dengan API call atau state management)
    const job = { 
        id: 1, title: 'Fullstack Developer', company: 'PasukanYerusSolo', 
        location: 'Solo', salary: '8jt', desc: 'Deskripsi lengkap pekerjaan di sini...' 
    };

    return (
        <div style={{ maxWidth: '800px', margin: '40px auto', padding: '20px', color: '#fef3c7' }}>
            <button onClick={() => navigate(-1)} style={{ marginBottom: '20px', cursor: 'pointer' }}>← Kembali</button>

            <div style={{ padding: '30px', background: '#120b06', borderRadius: '16px', border: '1px solid #262626' }}>
                <h1 style={{ color: '#ea580c' }}>{job.title}</h1>
                <p style={{ fontSize: '18px' }}>{job.company}</p>
                <div style={{ margin: '20px 0', padding: '20px 0', borderTop: '1px solid #262626' }}>
                    <h3>Deskripsi Pekerjaan</h3>
                    <p style={{ color: '#a3a3a3', lineHeight: '1.8' }}>{job.desc}</p>
                </div>
                <button style={{ padding: '12px 24px', background: '#ea580c', color: '#fff', border: 'none', borderRadius: '8px' }}>
                    Lamar Sekarang
                </button>
            </div>
        </div>
    );
};

export default JobDetail;
